import { useState } from 'react';
import '../index.css';

export function NavBar() {

    const [query,setQuery]=useState("");


    const opcije=["Beograd","Nis","Subotica","Novi Sad","Kraljevo","Kragujevac"];

 const filtrirani = opcije.filter((item) =>
    item.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <nav
      style={{
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        width: "100%",
        padding: "10px 40px",
        boxSizing: "border-box",
      }}
    >
       <div style={{ flex: 1, display: "flex", justifyContent: "center" }}>

          <input onChange={(e)=>setQuery(e.target.value)}/>

          {query &&



          <ul>
            {
                filtrirani.length>0?(filtrirani.map((mesto)=><li>{mesto}</li>)):(<li>Nema rezultata</li>)
            }


            </ul>
            }


      </div>
      <div style={{ display: "flex", gap: "10px" }}>
        <button className="btnNav">Register</button>
        <button className="btnNav">Login</button>
      </div>
    </nav>
  );
}

